// ============ 第4部分：工具函数 ============

function formatTime(ms: number): string {
  const diff = Date.now() - ms;
  const minutes = Math.floor(diff / 60000);
  const hours = Math.floor(diff / 3600000);
  if (minutes < 1) return "刚刚";
  if (minutes < 60) return `${minutes} 分钟前`;
  if (hours < 24) return `${hours} 小时前`;
  const d = new Date(ms);
  return `${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")} ${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
}

function extractChallenge(obj: any): any {
  if (!obj || typeof obj !== "object") return null;
  if (obj.challenge && typeof obj.challenge === "object") return obj.challenge;
  for (const key of Object.keys(obj)) {
    const found = extractChallenge(obj[key]);
    if (found) return found;
  }
  return null;
}

function readFileIfExists(filePath: string): string {
  try {
    if (fs.existsSync(filePath)) {
      return fs.readFileSync(filePath, "utf-8");
    }
  } catch {}
  return "";
}

// ============ 第4B部分：Hashline 编辑核心 ============

const HL_PREFIX = "#HL"
const fileRevCache = new Map<string, string>()

function hlHash(text: string, length: number): string {
  return crypto.createHash("sha1").update(text, "utf8").digest("hex").slice(0, length).toUpperCase()
}

function getHashLength(totalLines: number): number {
  return totalLines > 4096 ? 4 : 3
}

function lineHash(line: string, length: number): string {
  return hlHash(line, length)
}

function anchorHash(prevLine: string | undefined, line: string, nextLine: string | undefined, length: number): string {
  return hlHash(`${prevLine ?? ""}\u241E${line}\u241E${nextLine ?? ""}`, length)
}

function fileRev(raw: string): string {
  const normalized = raw.includes("\r\n") ? raw.replace(/\r\n/g, "\n") : raw
  return hlHash(normalized, 8)
}

function formatRev(rev: string): string {
  return `REV:${rev}`
}

function formatRef(lineNum: number, hash: string, anchor?: string): string {
  return anchor ? `${lineNum}#${hash}#${anchor}` : `${lineNum}#${hash}`
}

function formatAnnotatedLine(line: string, idx: number, lines: string[]): string {
  const len = getHashLength(Math.max(1, lines.length))
  return `${HL_PREFIX} ${formatRef(idx + 1, lineHash(line, len), anchorHash(lines[idx - 1], line, lines[idx + 1], len))}|${line}`
}

function annotateReadOutput(raw: string, filePath: string): string {
  const normalized = raw.includes("\r\n") ? raw.replace(/\r\n/g, "\n") : raw
  const endsWithNewline = normalized.endsWith("\n")
  let lines = normalized.split("\n")
  if (endsWithNewline && lines.length > 0 && lines[lines.length - 1] === "") lines.pop()

  const rev = fileRev(raw)
  fileRevCache.set(path.resolve(filePath), rev)

  const parts: string[] = []
  parts.push(`<hashline-file path="${filePath}" total_lines="${lines.length}">`)
  parts.push("# format: <line>#<hash>#<anchor>|<content>")
  parts.push("# use refs exactly as shown in hashline edit/patch tools")
  parts.push(`${HL_PREFIX} ${formatRev(rev)}`)
  for (let i = 0; i < lines.length; i++) {
    parts.push(formatAnnotatedLine(lines[i], i, lines))
  }
  parts.push("</hashline-file>")
  return parts.join("\n")
}

function parseLineRef(refStr: string): { lineNum: number; hash: string; anchor?: string } {
  const text = refStr.trim().replace(/^(?:#HL|;;;)\s*/i, "")
  const beforePipe = text.split("|")[0].trim()
  const match = beforePipe.match(/^(\d+)\s*[#: ]\s*([A-Za-z0-9]+)(?:\s*[#: ]\s*([A-Za-z0-9]+))?$/)
  if (!match) throw new Error(`Invalid line reference "${refStr}". Expected <line>#<hash> or <line>#<hash>#<anchor>`)
  return { lineNum: parseInt(match[1], 10), hash: match[2].toUpperCase(), anchor: match[3]?.toUpperCase() }
}

function findRefCandidates(parsed: ReturnType<typeof parseLineRef>, lines: string[], hashLen: number): number[] {
  const found: number[] = []
  for (let i = 0; i < lines.length; i++) {
    if (lineHash(lines[i], hashLen) !== parsed.hash) continue
    if (parsed.anchor && anchorHash(lines[i - 1], lines[i], lines[i + 1], hashLen) !== parsed.anchor) continue
    found.push(i)
  }
  return found
}

function resolveLineRef(ref: string, lines: string[], safeReapply: boolean): number {
  const parsed = parseLineRef(ref)
  if (parsed.lineNum > lines.length) {
    throw new Error(`Reference ${ref} points to line ${parsed.lineNum}, but file only has ${lines.length} lines`)
  }

  const hashLen = getHashLength(lines.length)
  const idx = parsed.lineNum - 1
  const actual = lines[idx]
  const actualHash = lineHash(actual, hashLen)
  const actualAnchor = anchorHash(lines[idx - 1], actual, lines[idx + 1], hashLen)

  if (actualHash !== parsed.hash || (parsed.anchor && actualAnchor !== parsed.anchor)) {
    if (safeReapply) {
      const candidates = findRefCandidates(parsed, lines, hashLen)
      if (candidates.length === 1) return candidates[0]
      if (candidates.length > 1) {
        throw new Error(`Hash mismatch; multiple relocation candidates (${candidates.map(c => c + 1).join(", ")}). Read the file again.`)
      }
      throw new Error("Hash mismatch; no relocation candidates found. Read the file again.")
    }
    const expected = parsed.anchor ? `${parsed.lineNum}#${parsed.hash}#${parsed.anchor}` : `${parsed.lineNum}#${parsed.hash}`
    const actualRef = `${parsed.lineNum}#${actualHash}#${actualAnchor}`
    throw new Error(`Hash mismatch for line ${parsed.lineNum}. Expected ${expected}, actual ${actualRef}. Read the file again.`)
  }
  return idx
}

interface HlOperation {
  op: "replace" | "delete" | "insert_before" | "insert_after" | "replace_range" | "set_file"
  ref?: string
  startRef?: string
  endRef?: string
  content?: string
}

interface ResolvedChange {
  spliceStart: number
  deleteCount: number
  insertLines: string[]
  order: number
  label: string
}

function splitToLines(content: string): string[] {
  const n = content.replace(/\r\n/g, "\n")
  if (!n) return []
  const parts = n.split("\n")
  if (n.endsWith("\n") && parts.length > 0) parts.pop()
  return parts
}

function resolveChanges(lines: string[], ops: HlOperation[], safeReapply: boolean): ResolvedChange[] {
  if (ops.length === 0) throw new Error("No operations provided")

  const setFileCount = ops.filter(o => o.op === "set_file").length
  if (setFileCount > 0 && ops.length > 1) throw new Error("set_file cannot be combined with other operations")

  return ops.map((op, order): ResolvedChange => {
    switch (op.op) {
      case "replace": {
        if (op.content === undefined) throw new Error("replace requires content")
        const s = resolveLineRef(op.startRef ?? op.ref!, lines, safeReapply)
        const e = op.endRef ? resolveLineRef(op.endRef, lines, safeReapply) : s
        if (s > e) throw new Error("replace startRef must be <= endRef")
        return { spliceStart: s, deleteCount: e - s + 1, insertLines: splitToLines(op.content), order, label: `replace(${op.startRef ?? op.ref}${op.endRef ? ".." + op.endRef : ""})` }
      }
      case "delete": {
        const s = resolveLineRef(op.startRef ?? op.ref!, lines, safeReapply)
        const e = op.endRef ? resolveLineRef(op.endRef, lines, safeReapply) : s
        if (s > e) throw new Error("delete startRef must be <= endRef")
        return { spliceStart: s, deleteCount: e - s + 1, insertLines: [], order, label: `delete(${op.startRef ?? op.ref}${op.endRef ? ".." + op.endRef : ""})` }
      }
      case "insert_before": {
        if (op.content === undefined) throw new Error("insert_before requires content")
        const s = resolveLineRef(op.startRef ?? op.ref!, lines, safeReapply)
        return { spliceStart: s, deleteCount: 0, insertLines: splitToLines(op.content), order, label: `insert_before(${op.startRef ?? op.ref})` }
      }
      case "insert_after": {
        if (op.content === undefined) throw new Error("insert_after requires content")
        const e = resolveLineRef(op.endRef ?? op.startRef ?? op.ref!, lines, safeReapply)
        return { spliceStart: e + 1, deleteCount: 0, insertLines: splitToLines(op.content), order, label: `insert_after(${op.endRef ?? op.startRef ?? op.ref})` }
      }
      case "replace_range": {
        if (!op.startRef || !op.endRef) throw new Error("replace_range requires startRef and endRef")
        if (op.content === undefined) throw new Error("replace_range requires content")
        const s = resolveLineRef(op.startRef, lines, safeReapply)
        const e = resolveLineRef(op.endRef, lines, safeReapply)
        if (s > e) throw new Error("replace_range startRef must be <= endRef")
        return { spliceStart: s, deleteCount: e - s + 1, insertLines: splitToLines(op.content), order, label: `replace_range(${op.startRef}..${op.endRef})` }
      }
      case "set_file": {
        if (op.content === undefined) throw new Error("set_file requires content")
        return { spliceStart: 0, deleteCount: lines.length, insertLines: splitToLines(op.content), order, label: "set_file" }
      }
      default:
        throw new Error(`Unsupported operation: ${(op as any).op}`)
    }
  })
}

function validateNoOverlap(changes: ResolvedChange[]): void {
  const taken = new Map<number, string>()
  for (const c of changes) {
    if (c.deleteCount === 0) continue
    for (let i = c.spliceStart; i < c.spliceStart + c.deleteCount; i++) {
      const existing = taken.get(i)
      if (existing) throw new Error(`Overlapping operations: ${c.label} conflicts with ${existing}`)
      taken.set(i, c.label)
    }
  }
}

function applyChanges(lines: string[], changes: ResolvedChange[]): string[] {
  const result = [...lines]
  const ordered = [...changes].sort((a, b) => {
    if (a.spliceStart !== b.spliceStart) return b.spliceStart - a.spliceStart
    return b.order - a.order
  })
  for (const c of ordered) {
    result.splice(c.spliceStart, c.deleteCount, ...c.insertLines)
  }
  return result
}

function applyHashlineEdit(filePath: string, raw: string, ops: HlOperation[], rev?: string, safeReapply?: boolean): string {
  if (rev) {
    const currentRev = fileRev(raw)
    if (currentRev !== rev.toUpperCase()) {
      throw new Error(`File revision mismatch for ${filePath}. Expected ${rev.toUpperCase()}, actual ${currentRev}. Read the file again.`)
    }
  }

  const normalized = raw.includes("\r\n") ? raw.replace(/\r\n/g, "\n") : raw
  const endsWithNewline = normalized.endsWith("\n")
  let lines = normalized.split("\n")
  if (endsWithNewline && lines.length > 0 && lines[lines.length - 1] === "") lines.pop()

  for (const op of ops) {
    if (op.content) op.content = stripHashlineAnnotations(op.content)
  }

  const changes = resolveChanges(lines, ops, safeReapply ?? false)
  validateNoOverlap(changes)
  const newLines = applyChanges(lines, changes)
  const eol = raw.includes("\r\n") ? "\r\n" : "\n"
  const result = newLines.length === 0 ? "" : newLines.join(eol) + (endsWithNewline ? eol : "")
  fileRevCache.delete(path.resolve(filePath))
  return result
}

function stripHashlineAnnotations(content: string): string {
  const wrapperRe = /^<\/?hashline-file\b/i
  const commentRe = /^#\s*(format|use refs|skipped|truncated)/i
  const revRe = /^#HL\s*REV:[A-F0-9]{8}$/i
  const refRe = /^([+\- ]?)#HL\s+\d+#[A-F0-9]+(?:#[A-F0-9]+)?\|/
  return content
    .split("\n")
    .filter(l => !wrapperRe.test(l.trim()) && !commentRe.test(l.trim()) && !revRe.test(l.trim()))
    .map(l => {
      const m = l.match(refRe)
      return m ? (m[1] ?? "") + l.slice(m[0].length) : l
    })
    .join("\n")
}

// ============ 第5部分：PowSolver ============

class PowSolver {
  async solve(challenge: any): Promise<number> {
    if (challenge.algorithm === "sha256") {
      return this.solveSha256(challenge);
    }
    if (challenge.algorithm === "DeepSeekHashV1") {
      return this.solveDeepSeekHash(challenge);
    }
    throw new Error(`Unsupported algorithm: ${challenge.algorithm}`);
  }

  private solveSha256(challenge: any): number {
    const { challenge: target, salt, difficulty } = challenge;
    let nonce = 0;
    while (true) {
      const hash = crypto
        .createHash("sha256")
        .update(salt + target + nonce)
        .digest("hex");
      let zeroBits = 0;
      for (const ch of hash) {
        const val = parseInt(ch, 16);
        if (val === 0) zeroBits += 4;
        else {
          zeroBits += Math.clz32(val) - 28;
          break;
        }
      }
      const targetDiff = difficulty > 1000 ? Math.floor(Math.log2(difficulty)) : difficulty;
      if (zeroBits >= targetDiff) return nonce;
      if (++nonce > 1_000_000) throw new Error("SHA256 PoW timeout");
    }
  }

  private async solveDeepSeekHash(challenge: any): Promise<number> {
    const wasmBuffer = Buffer.from(SHA3_WASM_B64, "base64");
    const { instance } = await WebAssembly.instantiate(wasmBuffer, { wbg: {} });
    const exports = instance.exports as any;
    const memory = exports.memory;
    const alloc = exports.__wbindgen_export_0;
    const addStack = exports.__wbindgen_add_to_stack_pointer;
    const wasmSolve = exports.wasm_solve;

    const encode = (str: string): [number, number] => {
      const buf = Buffer.from(str, "utf8");
      const ptr = alloc(buf.length, 1);
      new Uint8Array(memory.buffer).set(buf, ptr);
      return [ptr, buf.length];
    };

    const prefix = `${challenge.salt}_${challenge.expire_at}_`;
    const [ptrC, lenC] = encode(challenge.challenge);
    const [ptrP, lenP] = encode(prefix);
    const retptr = addStack(-16);
    wasmSolve(retptr, ptrC, lenC, ptrP, lenP, challenge.difficulty);
    addStack(16);

    const view = new DataView(memory.buffer);
    const status = view.getInt32(retptr, true);
    if (status === 0) throw new Error("DeepSeekHashV1 solve failed");
    return view.getFloat64(retptr + 8, true);
  }
}

// ============ 第6部分：DeepSeekClient（无状态）============

class DeepSeekClient {
  private powSolver = new PowSolver();

  constructor(private creds: Credentials) {}

  private async headers(): Promise<Record<string, string>> {
    return {
      Cookie: this.creds.cookie,
      "User-Agent": this.creds.userAgent,
      "Content-Type": "application/json",
      Accept: "*/*",
      Authorization: `Bearer ${this.creds.bearer}`,
      Referer: "https://chat.deepseek.com/",
      Origin: "https://chat.deepseek.com",
      "x-client-platform": "web",
      "x-client-version": "1.7.0",
      "x-app-version": "20241129.1",
      "x-client-locale": "zh_CN",
      "x-client-timezone-offset": "28800",
    };
  }

  async createChatSession(): Promise<string> {
    const targetPath = "/api/v0/chat_session/create";
    const res = await fetch(`https://chat.deepseek.com${targetPath}`, {
      method: "POST",
      headers: await this.headers(),
      body: JSON.stringify({}),
    });
    if (!res.ok) {
      const text = await res.text();
      throw new Error(`Failed to create chat session (${res.status}): ${text}`);
    }
    const data: any = await res.json();
    const sessionId =
      data?.data?.biz_data?.id ||
      data?.data?.biz_data?.chat_session_id ||
      data?.biz_data?.id ||
      data?.biz_data?.chat_session_id ||
      "";
    if (!sessionId) throw new Error("Empty chat session ID");
    return sessionId;
  }

  private async createPowChallenge(targetPath: string) {
    const res = await fetch(
      "https://chat.deepseek.com/api/v0/chat/create_pow_challenge",
      {
        method: "POST",
        headers: await this.headers(),
        body: JSON.stringify({ target_path: targetPath }),
      }
    );
    if (!res.ok) throw new Error(`PoW challenge failed (${res.status})`);
    const data: any = await res.json();
    const challenge =
      data?.data?.biz_data?.challenge ||
      data?.data?.challenge ||
      data?.challenge ||
      extractChallenge(data);
    if (!challenge) throw new Error("PoW challenge missing");
    return challenge;
  }

  async chat(
    sessionId: string,
    parentMessageId: number | null,
    message: string,
    thinkingEnabled: boolean,
    searchEnabled: boolean,
    signal?: AbortSignal
  ): Promise<ReadableStream<Uint8Array>> {
    const targetPath = "/api/v0/chat/completion";
    const challenge = await this.createPowChallenge(targetPath);
    const answer = await this.powSolver.solve(challenge);
    const powResponse = Buffer.from(
      JSON.stringify({ ...challenge, answer, target_path: targetPath })
    ).toString("base64");

    const body = JSON.stringify({
      chat_session_id: sessionId,
      parent_message_id: parentMessageId ?? null,
      prompt: message,
      ref_file_ids: [],
      thinking_enabled: thinkingEnabled,
      search_enabled: searchEnabled,
      preempt: false,
    });

    const res = await fetch(`https://chat.deepseek.com${targetPath}`, {
      method: "POST",
      headers: {
        ...(await this.headers()),
        "x-ds-pow-response": powResponse,
      },
      body,
      signal,
    });

    if (!res.ok) {
      const text = await res.text();
      throw new Error(`DeepSeek chat failed (${res.status}): ${text.slice(0, 200)}`);
    }
    return res.body!;
  }
}

// ============ 第7部分：StreamParser ============

class StreamParser {
  private tagBuffer = "";
  private currentMode: "text" | "thinking" | "tool_call" = "text";
  private currentToolName = "";
  private currentToolId = "";
  private currentToolArgs = "";
  private currentEventType = "";
  private events: ParseEvent[] = [];

  private emitText(content: string) {
    if (content) this.events.push({ type: "text_delta", content });
  }

  private emitThinking(content: string) {
    if (content) this.events.push({ type: "thinking_delta", content });
  }

  private emitToolCallDelta(argsDelta: string) {
    if (argsDelta) {
      this.events.push({
        type: "tool_call_delta",
        id: this.currentToolId,
        name: this.currentToolName,
        argsDelta,
      });
    }
  }

  private parseToolArgs(raw: string): Record<string, unknown> {
    try {
      return JSON.parse(raw.trim());
    } catch {
      return {};
    }
  }

  async *parse(stream: ReadableStream<Uint8Array>): AsyncGenerator<ParseEvent> {
    const reader = stream.getReader();
    const decoder = new TextDecoder();
    let lineBuffer = "";

    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        lineBuffer += decoder.decode(value, { stream: true });
        const lines = lineBuffer.split("\n");
        lineBuffer = lines.pop()!;
        for (const line of lines) {
          const trimmed = line.trim();
          if (!trimmed) continue;
          this.feedLine(trimmed);
        }
      }
      // 处理最后一行
      if (lineBuffer.trim()) {
        this.feedLine(lineBuffer.trim());
      }
    } catch (err: any) {
      if (err.name === "AbortError") {
        this.events.push({ type: "error", message: "请求已取消" });
        yield* this.flushEvents();
        return;
      }
      throw err;
    } finally {
      reader.releaseLock();
    }

    // 流结束，flush 残留
    this.feedLine(""); // 触 refresh
    this.flush();
    yield* this.flushEvents();
  }

  private feedLine(line: string) {
    if (line.startsWith("event: ")) {
      this.currentEventType = line.slice(7).trim();
      return;
    }

    if (!line.startsWith("data: ")) return;
    const jsonStr = line.slice(6);

    try {
      const data = JSON.parse(jsonStr);
      this.processData(data);
    } catch {
      // 忽略解析错误的行
    }
  }

  private processData(data: any) {
    // 捕获 message_id
    if (data.response_message_id !== undefined) {
      this.events.push({ type: "message_id", id: data.response_message_id });
    } else if (data.v?.response?.message_id !== undefined) {
      this.events.push({ type: "message_id", id: data.v.response.message_id });
    }

    // 捕获 title（通过 event: title + data.content）
    if (this.currentEventType === "title" && data.content) {
      this.events.push({ type: "title", title: data.content });
      this.currentEventType = "";
      return;
    }
    // 重置事件类型
    this.currentEventType = "";

    // 获取内容
    let content = "";
    if (typeof data.v === "string") {
      content = data.v;
    } else if (typeof data.content === "string") {
      content = data.content;
    } else if (data.v?.content && typeof data.v.content === "string") {
      content = data.v.content;
    } else if (data.v?.response?.fragments) {
      // 处理 fragments 数组（首段回复）
      const frags = data.v.response.fragments;
      for (const frag of frags) {
        if (frag.content) {
          const isThinking = frag.type === "THINKING" || data.p?.includes("reasoning");
          this.pushDelta(frag.content, isThinking ? "thinking" : undefined);
        }
      }
      return;
    }

    if (!content) return;

    // FINISHED 信号：自动闭合未结束的 tool_call
    if (content === "FINISHED" && this.currentMode === "tool_call") {
      let args: Record<string, unknown> = {};
      try { args = this.parseToolArgs(this.currentToolArgs); } catch {}
      this.events.push({
        type: "tool_call_end",
        id: this.currentToolId,
        name: this.currentToolName,
        arguments: args,
      });
      this.currentMode = "text";
      this.currentToolArgs = "";
      return;
    }
    if (content === "FINISHED") return;

    // 检查是否是 thinking 类型的 data
    if (data.p?.includes("reasoning") || data.type === "thinking") {
      this.pushDelta(content, "thinking");
    } else {
      this.pushDelta(content);
    }
  }

  private pushDelta(delta: string, forceType?: "text" | "thinking") {
    if (!delta) return;

    // JUNK_TOKENS 过滤
    if (JUNK_TOKENS.includes(delta)) {
      return;
    }

    if (forceType === "thinking") {
      this.emitThinking(delta);
      return;
    }

    this.tagBuffer += delta;
    this.checkTags();
  }

  private checkTags() {
    const thinkStartMatch = this.tagBuffer.match(/<(?:think(?:ing)?|thought)\b[^<>]*>/i);
    const thinkEndMatch = this.tagBuffer.match(/<\/(?:think(?:ing)?|thought)\b[^<>]*>/i);
    const toolCallStartMatch =
      this.tagBuffer.match(
        /<tool_call\s+(?:id=['"]?([^'"]+)['"]?\s+)?name=['"]?([^'"]+)['"]?(?:\s+id=['"]?([^'"]+)['"]?)?\s*>/i,
      ) ||
      this.tagBuffer.match(/<tool_call\s+id=['"]?([^'"]+)['"]?\s*>/i);
    const toolCallEndMatch = this.tagBuffer.match(/<\/tool_call\b[^<>]*>/i);
    const finalStartMatch = this.tagBuffer.match(/<final\b[^<>]*>/i);
    const finalEndMatch = this.tagBuffer.match(/<\/final\b[^<>]*>/i);
    const replyMatch = this.tagBuffer.match(/\[\[reply_to_current\]\]/i);
    const malformedThinkMatch = this.tagBuffer.match(/\n?think\s*>/i);

    const indices: {
      type: string;
      idx: number;
      len: number;
      id?: string | null;
      name?: string;
    }[] = [
      { type: "think_start", idx: thinkStartMatch ? thinkStartMatch.index! : -1, len: thinkStartMatch ? thinkStartMatch[0].length : 0 },
      { type: "think_end", idx: thinkEndMatch ? thinkEndMatch.index! : -1, len: thinkEndMatch ? thinkEndMatch[0].length : 0 },
      { type: "final_start", idx: finalStartMatch ? finalStartMatch.index! : -1, len: finalStartMatch ? finalStartMatch[0].length : 0 },
      { type: "final_end", idx: finalEndMatch ? finalEndMatch.index! : -1, len: finalEndMatch ? finalEndMatch[0].length : 0 },
      {
        type: "tool_call_start",
        idx: toolCallStartMatch ? toolCallStartMatch.index! : -1,
        len: toolCallStartMatch ? toolCallStartMatch[0].length : 0,
        id: toolCallStartMatch ? toolCallStartMatch[3] || toolCallStartMatch[1] : null,
        name: toolCallStartMatch ? toolCallStartMatch[2] || toolCallStartMatch[1] || "" : "",
      },
      { type: "tool_call_end", idx: toolCallEndMatch ? toolCallEndMatch.index! : -1, len: toolCallEndMatch ? toolCallEndMatch[0].length : 0 },
      { type: "reply_marker", idx: replyMatch ? replyMatch.index! : -1, len: replyMatch ? replyMatch[0].length : 0 },
      { type: "think_start", idx: malformedThinkMatch ? malformedThinkMatch.index! : -1, len: malformedThinkMatch ? malformedThinkMatch[0].length : 0 },
    ]
      .filter((tag) => tag.idx !== -1)
      .sort((a, b) => a.idx - b.idx);

    if (indices.length === 0) return;

    const first = indices[0];
    const before = this.tagBuffer.slice(0, first.idx);

    if (before) {
      if (this.currentMode === "thinking") {
        this.emitThinking(before);
      } else if (this.currentMode === "tool_call") {
        this.currentToolArgs += before;
        this.emitToolCallDelta(before);
      } else {
        this.emitText(before);
      }
    }

    if (first.type === "think_start") {
      this.currentMode = "thinking";
    } else if (first.type === "think_end") {
      this.currentMode = "text";
    } else if (first.type === "tool_call_start") {
      this.currentMode = "tool_call";
      this.currentToolName = first.name!;
      this.currentToolId = first.id || "";
      this.currentToolArgs = "";
      this.events.push({
        type: "tool_call_start",
        id: this.currentToolId,
        name: this.currentToolName,
      });
    } else if (first.type === "tool_call_end") {
      // 解析累积的 args
      let parsedArgs: Record<string, unknown> = {};
      try {
        parsedArgs = this.parseToolArgs(this.currentToolArgs);
      } catch {
        // args 解析失败时使用空对象
      }
      this.events.push({
        type: "tool_call_end",
        id: this.currentToolId,
        name: this.currentToolName,
        arguments: parsedArgs,
      });
      this.currentMode = "text";
      this.currentToolArgs = "";
    } else if (first.type === "final_start" || first.type === "final_end" || first.type === "reply_marker") {
      this.currentMode = "text";
    }

    // 切掉已处理部分
    this.tagBuffer = this.tagBuffer.slice(first.idx + first.len);

    // 递归检查剩余 buffer 中的标签
    if (this.tagBuffer) {
      this.checkTags();
    }
  }

  flush() {
    if (this.tagBuffer) {
      if (this.currentMode === "thinking") {
        this.emitThinking(this.tagBuffer);
      } else if (this.currentMode === "tool_call") {
        this.currentToolArgs += this.tagBuffer;
        this.emitToolCallDelta(this.tagBuffer);
        // 未闭合的 tool_call，自动闭合
        let args: Record<string, unknown> = {};
        try { args = this.parseToolArgs(this.currentToolArgs); } catch {}
        this.events.push({
          type: "tool_call_end",
          id: this.currentToolId,
          name: this.currentToolName,
          arguments: args,
        });
      } else {
        this.emitText(this.tagBuffer);
      }
      this.tagBuffer = "";
    }
    this.events.push({ type: "end" });
  }

  private *flushEvents(): Generator<ParseEvent> {
    while (this.events.length > 0) {
      yield this.events.shift()!;
    }
  }
}

// ============ 第8部分：SessionStore ============

class SessionStore {
  constructor(private workDir: string) {}

  private get sessionsDir(): string {
    return path.join(this.workDir, ".deepseek", "sessions");
  }

  private sessionFile(id: string): string {
    return path.join(this.sessionsDir, `${id}.json`);
  }

  save(state: SessionState): void {
    if (!state.id) return;
    state.updatedAt = Date.now();
    fs.mkdirSync(this.sessionsDir, { recursive: true });
    fs.writeFileSync(this.sessionFile(state.id), JSON.stringify(state, null, 2));
  }

  load(id: string): SessionState | null {
    const file = this.sessionFile(id);
    if (!fs.existsSync(file)) return null;
    try {
      return JSON.parse(fs.readFileSync(file, "utf-8")) as SessionState;
    } catch {
      console.warn(`⚠️ 会话文件损坏: ${file}`);
      return null;
    }
  }

  delete(id: string): void {
    const file = this.sessionFile(id);
    if (fs.existsSync(file)) fs.unlinkSync(file);
    const currentId = this.getCurrentId();
    if (currentId === id) this.setCurrentId("");
  }

  list(): { id: string; title: string; rounds: number; updatedAt: number; forkedFrom?: string; forkedFromTitle?: string }[] {
    const dir = this.sessionsDir;
    if (!fs.existsSync(dir)) return [];
    const result: { id: string; title: string; rounds: number; updatedAt: number; forkedFrom?: string; forkedFromTitle?: string }[] = [];
    const files = fs.readdirSync(dir).filter((f) => f.endsWith(".json") && f !== "_current");
    for (const file of files) {
      const filePath = path.join(dir, file);
      try {
        const data = JSON.parse(fs.readFileSync(filePath, "utf-8"));
        const item: any = {
          id: data.id || file.replace(".json", ""),
          title: data.title || "新会话",
          rounds: Math.ceil((data.messages?.length || 0) / 2),
          updatedAt: data.updatedAt || 0,
        };
        if (data.forkedFrom) {
          item.forkedFrom = data.forkedFrom;
          // 获取原始会话标题
          try {
            const orig = JSON.parse(fs.readFileSync(this.sessionFile(data.forkedFrom), "utf-8"));
            item.forkedFromTitle = orig.title || data.forkedFrom.slice(0, 8);
          } catch {
            item.forkedFromTitle = data.forkedFrom.slice(0, 8);
          }
        }
        result.push(item);
      } catch {
        console.warn(`⚠️ 跳过损坏文件: ${file}`);
      }
    }
    result.sort((a, b) => b.updatedAt - a.updatedAt);
    return result;
  }

  getCurrentId(): string | null {
    const file = path.join(this.sessionsDir, "_current");
    if (!fs.existsSync(file)) return null;
    const id = fs.readFileSync(file, "utf-8").trim();
    return id || null;
  }

  setCurrentId(id: string): void {
    fs.mkdirSync(this.sessionsDir, { recursive: true });
    fs.writeFileSync(path.join(this.sessionsDir, "_current"), id);
  }
}

// ============ 第9部分：ToolRegistry & ToolExecutor ============

class ToolRegistry {
  private tools: Map<string, ToolDefinition> = new Map();

  register(tool: ToolDefinition): void {
    this.tools.set(tool.name, tool);
  }

  find(name: string): ToolDefinition | undefined {
    return this.tools.get(name);
  }

  list(): ToolDefinition[] {
    return Array.from(this.tools.values());
  }

  buildToolPrompt(): string {
    const tools = this.list();
    if (tools.length === 0) return "";
    let text = "## Available Tools\n";
    for (const t of tools) {
      text += `- ${t.name}: ${t.description}\n`;
    }
    text += `\n需要时回复 <tool_call name="工具名">\n{"参数名":"参数值"}\n</tool_call>\n不需要则直接回答。`;
    return text;
  }
}

class ToolExecutor {
  constructor(private registry: ToolRegistry) {}

  private async askConfirm(question: string): Promise<boolean> {
    process.stdout.write(question);
    const answer = await new Promise<string>((resolve) => {
      process.stdin.once("data", (buf: Buffer) => {
        resolve(buf.toString().trim().toLowerCase());
      });
    });
    return answer === "y" || answer === "yes";
  }

  async execute(name: string, args: Record<string, unknown>, rl?: readline.Interface): Promise<string> {
    const tool = this.registry.find(name);
    if (!tool) return `Error: Unknown tool: ${name}`;

    // 写操作需要确认
    if (name === "write" || name === "exec" || name === "edit") {
      if (rl) rl.pause();
      try {
        const confirmed = await this.askConfirm(`⚠️ 确认执行 ${name}？(y/n) `);
        if (!confirmed) return "用户取消了操作";
      } finally {
        if (rl) rl.resume();
      }
    }

    return this.runTool(name, args);
  }

  private runTool(name: string, args: Record<string, unknown>): string {
    try {
      switch (name) {
        case "read": {
          const raw = fs.readFileSync(args.path as string, "utf-8");
          return annotateReadOutput(raw, args.path as string);
        }
        case "write": {
          const clean = stripHashlineAnnotations(args.content as string);
          fs.writeFileSync(args.path as string, clean);
          fileRevCache.delete(path.resolve(args.path as string));
          return "success";
        }
        case "edit": {
          const filePath = args.filePath as string;
          const raw = fs.readFileSync(filePath, "utf-8");
          const ops = (args.operations ?? []) as HlOperation[];
          const rev = args.fileRev as string | undefined;
          const safe = args.safeReapply as boolean | undefined;
          const result = applyHashlineEdit(filePath, raw, ops, rev, safe);
          fs.writeFileSync(filePath, result);
          return `Edit applied: ${ops.length} operation(s)`;
        }
        case "exec":
          return execSync(args.command as string, {
            encoding: "utf-8",
            timeout: 30000,
            stdio: "pipe",
          }).toString();
        default:
          return `Error: Not implemented: ${name}`;
      }
    } catch (err: any) {
      return `Error: ${err.message}`;
    }
  }
}

function registerBuiltinTools(registry: ToolRegistry): void {
  registry.register({
    name: "read",
    description: "Read file content from a given path.",
    parameters: { path: { type: "string", description: "File path" } },
  });
  registry.register({
    name: "write",
    description: "Write content to a file.",
    parameters: {
      path: { type: "string", description: "File path" },
      content: { type: "string", description: "Content to write" },
    },
  });
  registry.register({
    name: "edit",
    description: "Edit a file using hashline refs from read output. Args: filePath, operations (array of {op, startRef?, endRef?, ref?, content?}), fileRev?, safeReapply?. Ops: replace/delete/insert_before/insert_after/replace_range. use refs exactly as shown in read output.",
    parameters: {
      filePath: { type: "string", description: "Path to the file" },
      operations: { type: "string", description: "JSON array of operations with startRef/endRef from read output" },
      fileRev: { type: "string", description: "REV token from read output to detect stale edits" },
      safeReapply: { type: "string", description: "Allow relocating refs if hash matches but line moved" },
    },
  });
  registry.register({
    name: "exec",
    description: "Execute a system command and return the output.",
    parameters: { command: { type: "string", description: "Command to run" } },
  });
}

// ============ 第11部分：PromptBuilder ============

class PromptBuilder {
  constructor(private workDir: string) {}

  build(
    systemPrompt: string,
    toolsPrompt: string,
    userMessage: string,
    isFirstTurn: boolean,
    toolMdContent?: string,
    skillMdContent?: string
  ): string {
    if (!isFirstTurn) {
      return userMessage;
    }
    const parts: string[] = [];
    if (systemPrompt) parts.push(systemPrompt);
    if (toolsPrompt) parts.push(toolsPrompt);
    if (toolMdContent) parts.push(toolMdContent);
    if (skillMdContent) parts.push(skillMdContent);
    parts.push(`User: ${userMessage}`);
    return parts.join("\n\n");
  }
}

// ============ 第12部分：ChatSession（核心协调器）============

class ChatSession {
  private state: SessionState;
  private reinjectMode: "new" | "keep" | null = null;
  private _ac: AbortController | null = null;
  private systemPromptCache = "";
  private toolsPrompt = "";
  private rl: readline.Interface | null = null;

  constructor(
    state: SessionState,
    private client: DeepSeekClient,
    private store: SessionStore,
    private promptBuilder: PromptBuilder,
    private toolExecutor: ToolExecutor
  ) {
    this.state = state;
  }

  get sessionId(): string { return this.state.id; }
  get title(): string { return this.state.title; }
  get thinkEnabled(): boolean { return this.state.thinkEnabled; }
  get searchEnabled(): boolean { return this.state.searchEnabled; }
  get parentMessageId(): number | null { return this.state.parentMessageId; }
  get messageCount(): number { return this.state.messages.length; }
  get reinjectMode(): "new" | "keep" | null { return this.reinjectMode; }
  get messages(): MessageRecord[] { return this.state.messages; }
  set messages(v: MessageRecord[]) { this.state.messages = v; }
  get forkedFrom(): string | undefined { return this.state.forkedFrom; }
  set forkedFrom(v: string | undefined) { this.state.forkedFrom = v; }
  setId(id: string): void { this.state.id = id; }
  touch(): void { this.state.updatedAt = Date.now(); }

  setThinkEnabled(v: boolean): void { this.state.thinkEnabled = v; }
  setSearchEnabled(v: boolean): void { this.state.searchEnabled = v; }
  setParentMessageId(id: number | null): void { this.state.parentMessageId = id; }
  setReinjectMode(m: "new" | "keep" | null): void { this.reinjectMode = m; }
  setSystemPrompt(p: string): void { this.systemPromptCache = p; }
  setToolsPrompt(p: string): void { this.toolsPrompt = p; }
  setRl(rl: readline.Interface | null): void { this.rl = rl; }
  setClient(creds: Credentials): void { this.client = new DeepSeekClient(creds); }
  setTitle(t: string): void { this.state.title = t; }
  addMessage(m: MessageRecord): void { this.state.messages.push(m); }
  save(): void {
    if (this.state.id) {
      this.store.save(this.state);
    }
  }

  abort(): void {
    if (this._ac) {
      this._ac.abort();
      this._ac = null;
    }
  }

  async *send(userMessage: string, rawMode: boolean): AsyncGenerator<ParseEvent> {
    this._ac = new AbortController();

    // 处理 reinject
    let isFirstTurn = this.state.parentMessageId === null;
    if (this.reinjectMode === "new") {
      this.state.parentMessageId = null;
      isFirstTurn = true;
      this.reinjectMode = null;
    } else if (this.reinjectMode === "keep") {
      isFirstTurn = true;
      this.reinjectMode = null;
    }

    // 构建 prompt
    const prompt = this.promptBuilder.build(
      this.systemPromptCache, this.toolsPrompt, userMessage, isFirstTurn
    );

    // 惰性创建 sessionId
    if (!this.state.id) {
      try {
        const realId = await this.client.createChatSession();
        this.state.id = realId;
        this.store.setCurrentId(realId);
      } catch (err: any) {
        yield { type: "error", message: `创建会话失败: ${err.message}` };
        return;
      }
    }

    // 工具调用循环（最大 10 次）
    let currentPrompt = prompt;
    let currentParentId = this.state.parentMessageId;
    let depth = 0;
    const MAX_TOOL_CALLS = 10;
    let assistantText = "";
    let foundToolCall = false;

    while (depth <= MAX_TOOL_CALLS) {
      foundToolCall = false;
      let stream: ReadableStream<Uint8Array>;
      try {
        stream = await this.client.chat(
          this.state.id, currentParentId, currentPrompt,
          this.state.thinkEnabled, this.state.searchEnabled, this._ac.signal
        );
      } catch (err: any) {
        if (err.name === "AbortError") {
          yield { type: "error", message: "请求已取消" };
        } else if (err.message?.includes("401")) {
          yield { type: "error", message: `凭证已过期 (401): ${err.message}` };
        } else {
          yield { type: "error", message: `网络错误: ${err.message}` };
        }
        return;
      }

      // 原始模式：直接输出原始 SSE，不走 parsing
      if (rawMode) {
        const reader = stream.getReader();
        const decoder = new TextDecoder();
        try {
          let rawText = "";
          while (true) {
            const { done, value } = await reader.read();
            if (done) break;
            const chunk = decoder.decode(value, { stream: true });
            process.stdout.write(chunk);
            rawText += chunk;
          }
          if (rawText.trim()) {
            this.state.messages.push(
              { role: "user", content: userMessage, timestamp: Date.now(), parentMessageId: this.state.parentMessageId },
              { role: "assistant", content: rawText, timestamp: Date.now(), parentMessageId: this.state.parentMessageId }
            );
            this.state.updatedAt = Date.now();
            this.save();
          }
        } catch (err: any) {
          if (err.name !== "AbortError") yield { type: "error", message: `原始模式错误: ${err.message}` };
        } finally {
          reader.releaseLock();
        }
        yield { type: "end" };
        this._ac = null;
        return;
      }

      const parser = new StreamParser();

      for await (const event of parser.parse(stream)) {
        switch (event.type) {
          case "text_delta":
            assistantText += event.content;
            yield event;
            break;
          case "thinking_delta":
            assistantText += event.content;
            yield event;
            break;
          case "tool_call_end":
            foundToolCall = true;
            yield event;
            try {
              const result = await this.toolExecutor.execute(event.name, event.arguments);
              currentPrompt = `\n<tool_response id="" name="${event.name}">\n${result}\n</tool_response>\n\nPlease proceed based on this tool result.`;
            } catch (toolErr: any) {
              yield { type: "error", message: `工具执行失败: ${toolErr.message}` };
              return;
            }
            break;
          case "message_id":
            this.state.parentMessageId = event.id;
            currentParentId = event.id;
            break;
          case "title":
            this.state.title = event.title;
            break;
          case "error":
            yield event;
            break;
          case "end":
            yield event;
            break;
          default:
            yield event;
        }
      }

      if (!foundToolCall) break;
      depth++;
    }

    if (depth > MAX_TOOL_CALLS) {
      yield { type: "error", message: "工具调用超过最大次数限制" };
    }

    // 检测空回复（房间可能已被删除）
    if (!assistantText && !foundToolCall) {
      const historyRounds = Math.floor(this.state.messages.length / 2);
      yield { type: "error", message: "会话无响应，房间可能已被删除" };
      yield { type: "room_recovery", historyRounds };
      return;
    }

    this.pushUserAndAssistantMessages(userMessage, assistantText);
    this.state.updatedAt = Date.now();
    this.save();
    this._ac = null;
  }

  pushUserAndAssistantMessages(userText: string, assistantText: string): void {
    this.state.messages.push({
      role: "user", content: userText, timestamp: Date.now(),
      parentMessageId: this.state.parentMessageId,
    });
    if (assistantText) {
      this.state.messages.push({
        role: "assistant", content: assistantText, timestamp: Date.now(),
        parentMessageId: this.state.parentMessageId,
      });
    }
  }

  static create(
    client: DeepSeekClient, store: SessionStore,
    promptBuilder: PromptBuilder, executor: ToolExecutor, title?: string
  ): ChatSession {
    const state: SessionState = {
      id: "", title: title || "", parentMessageId: null,
      messages: [], thinkEnabled: false, searchEnabled: true,
      createdAt: Date.now(), updatedAt: Date.now(),
    };
    return new ChatSession(state, client, store, promptBuilder, executor);
  }

  static load(
    sessionId: string, client: DeepSeekClient, store: SessionStore,
    promptBuilder: PromptBuilder, executor: ToolExecutor
  ): ChatSession | null {
    const state = store.load(sessionId);
    if (!state) return null;
    return new ChatSession(state, client, store, promptBuilder, executor);
  }
}

// ============ 第13部分：环境发现 ============

function scanDeepseekDir(workDir: string): {
  systemPrompt: string;
  systemSource: "local" | "global" | "none";
  toolMdContent: string;
  skillMdContent: string;
} {
  const deepseekDir = path.join(workDir, ".deepseek");
  const localSystem = readFileIfExists(path.join(deepseekDir, "system.md"));
  const globalSystem = readFileIfExists(path.join(deepseekDir, "system-all.md"));
  const toolMd = readFileIfExists(path.join(deepseekDir, "tool.md"));
  const skillMd = readFileIfExists(path.join(deepseekDir, "skill.md"));

  if (localSystem) {
    return { systemPrompt: localSystem, systemSource: "local", toolMdContent: toolMd, skillMdContent: skillMd };
  }
  if (globalSystem) {
    return { systemPrompt: globalSystem, systemSource: "global", toolMdContent: toolMd, skillMdContent: skillMd };
  }
  return { systemPrompt: "", systemSource: "none", toolMdContent: toolMd, skillMdContent: skillMd };
}

// ============ 第14部分：登录与凭证管理 ============

function openInChrome(url: string): void {
  if (IS_ANDROID) {
    try {
      execSync(
        `am start -a android.intent.action.VIEW -d "${url}"` +
          ` -n com.android.chrome/org.chromium.chrome.browser.ChromeTabbedActivity`,
        { stdio: "ignore", timeout: 3000 }
      );
    } catch {}
  }
}

async function loginDeepseek(
  onProgress: (msg: string) => void
): Promise<Credentials> {
  // 平台伪装：支持在 Termux/Android 上运行 Playwright
  if (process.platform === "android") {
    Object.defineProperty(process, "platform", { value: "linux" });
  }
  const CDP_URL = "http://127.0.0.1:9222";
  let chromium: any;
  try {
    const mod = await import("playwright-core");
    chromium = mod.chromium;
  } catch (e: any) {
    const msg = e?.message || String(e);
    throw new Error(
      `无法加载 playwright-core: ${msg}\n` +
      "请运行: npm install playwright-core\n" +
      "playwright-core 用于通过 Chrome DevTools Protocol (CDP) 连接浏览器自动捕获登录凭证。\n" +
      "仅登录时需要，对话过程不依赖。"
    );
  }

  onProgress("正在检查 Chrome 调试端口...");
  let versionRes: Response;
  try {
    versionRes = await fetch(`${CDP_URL}/json/version`, {
      signal: AbortSignal.timeout(5000),
    });
  } catch {
    throw new Error("无法连接 Chrome。请先启动带 --remote-debugging-port=9222 的 Chrome");
  }
  const versionData: any = await versionRes.json();
  const wsUrl = versionData.webSocketDebuggerUrl;
  if (!wsUrl) throw new Error("未找到 WebSocket 调试 URL");

  onProgress("正在连接浏览器...");
  const browser = await chromium.connectOverCDP(wsUrl);
  const context = browser.contexts()[0] ?? (await browser.newContext());

  let userAgent = "";
  try {
    const pages = context.pages();
    if (pages.length > 0) {
      userAgent = await pages[0].evaluate(() => navigator.userAgent);
    } else {
      const tempPage = await context.newPage();
      userAgent = await tempPage.evaluate(() => navigator.userAgent);
      await tempPage.close();
    }
  } catch {
    throw new Error("无法从浏览器获取 User-Agent");
  }
  if (!userAgent) throw new Error("User-Agent 为空");

  const existingCookies = await context.cookies([
    "https://chat.deepseek.com",
    "https://deepseek.com",
  ]);
  const cookieStr = existingCookies
    .map((c: any) => `${c.name}=${c.value}`)
    .join("; ");

  onProgress("正在检查现有登录态...");
  let bearer = "";
  try {
    const checkRes = await fetch("https://chat.deepseek.com/api/v0/users/current", {
      headers: {
        Cookie: cookieStr,
        "User-Agent": userAgent,
        Accept: "application/json",
        Referer: "https://chat.deepseek.com/",
        Origin: "https://chat.deepseek.com",
      },
    });
    if (checkRes.ok) {
      const data: any = await checkRes.json();
      bearer = data?.data?.biz_data?.token || "";
      if (bearer) {
        onProgress("发现有效登录态，无需重新登录！");
        await browser.close();
        return { cookie: cookieStr, bearer, userAgent };
      }
    }
  } catch {}

  onProgress("未发现有效登录态，开始登录流程...");

  let page = context.pages().find((p: any) =>
    p.url().includes("chat.deepseek.com")
  );
  if (!page) {
    openInChrome("https://chat.deepseek.com");
    onProgress("等待 DeepSeek 页面在 Chrome 中打开...");
    for (let i = 0; i < 10; i++) {
      await new Promise((r) => setTimeout(r, 1000));
      page = context.pages().find((p: any) =>
        p.url().includes("chat.deepseek.com")
      );
      if (page) break;
    }
    if (!page) {
      throw new Error("无法自动打开 DeepSeek 页面，请手动在 Chrome 中打开 chat.deepseek.com 后重试");
    }
  } else {
    onProgress("切换到已有的 DeepSeek 标签页...");
    await page.bringToFront();
  }

  onProgress("请在浏览器窗口中登录 DeepSeek，凭证会自动捕获...");
  let capturedBearer = "";
  let resolved = false;

  page.on("request", (req: any) => {
    if (resolved) return;
    if (req.url().includes("/api/v0/")) {
      const auth = req.headers()["authorization"];
      if (auth?.startsWith("Bearer ") && !capturedBearer) {
        capturedBearer = auth.slice(7);
        onProgress("已捕获 Bearer Token");
      }
    }
  });

  page.on("response", async (resp: any) => {
    if (resolved || capturedBearer) return;
    if (resp.url().includes("/api/v0/users/current") && resp.ok()) {
      try {
        const body: any = await resp.json();
        const token = body?.data?.biz_data?.token;
        if (token) {
          capturedBearer = token;
          onProgress("从 API 响应中提取到 Bearer Token");
        }
      } catch {}
    }
  });

  try {
    const result = await new Promise<Credentials>((resolve, reject) => {
      const timeout = setTimeout(
        () => reject(new Error("登录超时（5 分钟）")),
        300_000
      );
      const interval = setInterval(async () => {
        if (resolved) return;
        if (!capturedBearer) return;
        const cookies = await context.cookies([
          "https://chat.deepseek.com",
          "https://deepseek.com",
        ]);
        const cStr = cookies
          .map((c: any) => `${c.name}=${c.value}`)
          .join("; ");
        if (cStr.includes("d_id=") || cStr.includes("ds_session_id=")) {
          resolved = true;
          clearTimeout(timeout);
          clearInterval(interval);
          resolve({ cookie: cStr, bearer: capturedBearer, userAgent });
        }
      }, 2000);
    });
    return result;
  } finally {
    await browser.close();
  }
}

function saveCredentials(cred: Credentials): void {
  fs.writeFileSync(CRED_FILE, JSON.stringify(cred, null, 2));
}

function loadCredentials(): Credentials | null {
  try {
    if (!fs.existsSync(CRED_FILE)) return null;
    return JSON.parse(fs.readFileSync(CRED_FILE, "utf-8")) as Credentials;
  } catch {
    return null;
  }
}

async function verifyCredentials(
  cred: Credentials
): Promise<{ valid: boolean; email?: string }> {
  try {
    const res = await fetch("https://chat.deepseek.com/api/v0/users/current", {
      headers: {
        Cookie: cred.cookie,
        "User-Agent": cred.userAgent,
        Accept: "application/json",
        Referer: "https://chat.deepseek.com/",
        Origin: "https://chat.deepseek.com",
      },
    });
    if (res.ok) {
      const data: any = await res.json();
      const email = data?.data?.biz_data?.email || data?.data?.email || "";
      return { valid: true, email };
    }
    return { valid: false };
  } catch {
    return { valid: false };
  }
}

async function ensureCredentials(
  log: (msg: string) => void
): Promise<Credentials> {
  let cred = loadCredentials();
  if (!cred || !cred.bearer || !cred.cookie) {
    if (cred && !cred.bearer) {
      log("凭证文件损坏，触发自动登录...");
    } else {
      log("凭证缺失，启动登录流程...");
    }
    cred = await loginDeepseek(log);
    saveCredentials(cred);
    return cred;
  }

  const { valid } = await verifyCredentials(cred);
  if (!valid) {
    log("凭证已过期，启动登录流程...");
    cred = await loginDeepseek(log);
    saveCredentials(cred);
  }
  return cred;
}
// ============ 第15部分：命令处理器 ============

type ReplCtx = {
  client: DeepSeekClient;
  store: SessionStore;
  promptBuilder: PromptBuilder;
  toolRegistry: ToolRegistry;
  toolExecutor: ToolExecutor;
  creds: Credentials;
  workDir: string;
  rl: readline.Interface;
  rawMode: boolean;
};

type CommandResult =
  | { type: "session"; value: ChatSession | null }
  | { type: "quit" }
  | { type: "load_interactive" }
  | { type: "confirm"; action: string; id?: string; newId?: number; mode?: string }
  | { type: "cd_switched"; dir: string }

async function handleCommand(
  line: string,
  session: ChatSession | null,
  ctx: ReplCtx
): Promise<ChatSession | null | CommandResult> {
  const parts = line.slice(1).trim().split(/\s+/);
  const cmd = parts[0];
  const args = parts.slice(1);

  const log = (msg: string) => console.log(msg);

  switch (cmd) {
    case "new": {
      const title = args.join(" ") || undefined;
      session = ChatSession.create(ctx.client, ctx.store, ctx.promptBuilder, ctx.toolExecutor, title);
      session.setRl(ctx.rl);
      ctx.store.setCurrentId(session.sessionId);
      const env = scanDeepseekDir(ctx.workDir);
      session.setSystemPrompt(env.systemPrompt);
      // 不自动注入工具提示词，避免干扰内置搜索

      log(`✅ 已创建新会话${title ? ` ${title}` : ""}`);
      return session;
    }

    case "load": {
      const id = args[0];
      if (!id) {
        // 交互式：显示列表让用户选择
        const list = ctx.store.list();
        if (list.length === 0) { log("暂无保存的会话"); return session; }
        log("请输入要切换的会话序号，或 q 退出：\n");
        list.forEach((s, i) => {
          log(`   [${i + 1}] ${s.id} - ${s.title} (${s.rounds} 轮)`);
          if (s.forkedFrom) log(`        ↳ fork 自 [${s.forkedFrom.slice(0, 8)}] ${s.forkedFromTitle || ""}`);
        });
        return { type: "load_interactive" } as CommandResult;
      }
      if (session) {
        session.abort();
        session.save();
      }
      const loaded = ChatSession.load(id, ctx.client, ctx.store, ctx.promptBuilder, ctx.toolExecutor);
      if (!loaded) {
        log(`❌ 未找到会话 ${id}，可用会话：`);
        const list = ctx.store.list();
        if (list.length === 0) log("  暂无保存的会话");
        else list.forEach((s, i) => {
          const fork = s.forkedFrom ? `, fork 自 ${s.forkedFrom.slice(0, 8)}` : "";
          log(`   ${i + 1}  ID: ${s.id}  ·  ${s.title}  ·  ${s.rounds} 轮${fork}`);
        });
        log("请输入 /load <id> 切换");
        return session;
      }
      loaded.setRl(ctx.rl);
      ctx.store.setCurrentId(loaded.sessionId);
      log(`📎 已切换到：${loaded.sessionId} - ${loaded.title} (${loaded.messageCount} 轮)`);
      return loaded;
    }

    case "ls": case "list": {
      const list = ctx.store.list();
      log(`📂 当前工作目录: ${ctx.workDir}`);
      if (list.length === 0) {
        log("  暂无保存的会话");
      } else {
        log(`  共 ${list.length} 个会话：\n`);
        list.forEach((s, i) => {
          const fork = s.forkedFrom ? ` (fork 自 ${s.forkedFrom})` : "";
          const time = formatTime(s.updatedAt);
          log(`   ${i + 1}  ID: ${s.id}  ·  ${s.title}  ·  ${s.rounds} 轮  ·  ${time}${fork}`);
        });
      }
      return session;
    }

    case "del": case "delete": {
      if (args[0] === "--all") {
        // 进入删除子模式
        return session; // 实际由 REPL 层处理
      }
      const id = args[0];
      if (id) {
        const target = ctx.store.load(id);
        if (!target) { log(`❌ 未找到会话 ${id}`); return session; }
        log(`⚠️ 确认删除会话 ${id} - ${target.title}？(y/n)`);
        return { type: "confirm", action: "DEL_SINGLE", id } as CommandResult;
      }
      // 无参数：返回标志给 REPL 进入删除子模式
      return session;
    }

    case "p": case "parent": {
      const id = args[0];
      if (!id || !session) { log("❌ 用法: /p <id>"); return session; }
      const newId = parseInt(id, 10);
      if (isNaN(newId)) { log("❌ id 必须是数字"); return session; }
      log(`⚠️ 续接点将被修改 (原: ${session.parentMessageId} → 新: ${newId})，确认？(y/n)`);
      return { type: "confirm", action: "PARENT", newId } as CommandResult;
    }

    case "f": case "fork": {
      if (!session || session.messageCount === 0) {
        log("⚠️ 当前会话无历史消息，无法 fork");
        return session;
      }
      const forkId = args[0] ? parseInt(args[0], 10) : undefined;
      const title = args.slice(forkId !== undefined ? 1 : 0).join(" ") || undefined;

      // 构建历史文本
      const messages = session.messages;
      const stopIdx = forkId !== undefined ? messages.findIndex((m: MessageRecord) => m.messageId === forkId) + 1 : messages.length;
      const historyParts: string[] = [];
      let i = 0;
      while (i < stopIdx && i < messages.length) {
        const m = messages[i];
        historyParts.push(`${m.role === "user" ? "User" : "Assistant"}: ${m.content}`);
        i++;
      }
      const historyText = historyParts.join("\n");

      try {
        const forkSession = ChatSession.create(ctx.client, ctx.store, ctx.promptBuilder, ctx.toolExecutor, title);
        // 注入历史到新会话
        forkSession.messages = messages.slice(0, stopIdx);
        forkSession.forkedFrom = session.sessionId;
        if (!title && session.title) forkSession.setTitle(`${session.title} - 分支`);

        const newId = await ctx.client.createChatSession();
        forkSession.setId(newId);
        forkSession.setParentMessageId(null);

        // 新会话首轮注入历史
        const env = scanDeepseekDir(ctx.workDir);
        forkSession.setSystemPrompt(env.systemPrompt);
        forkSession.save();
        ctx.store.setCurrentId(newId);
        session = forkSession;
        log(`✅ 已分叉新会话: ${session.title}`);
      } catch (err: any) {
        log(`❌ fork 失败: ${err.message}`);
      }
      return session;
    }

    case "s": case "save": {
      if (!session) { log("❌ 没有活跃会话"); return session; }
      if (!session.sessionId) { log("💡 会话尚未创建（首次发送消息后自动创建）"); return session; }
      session.save();
      log(`✅ 已保存会话`);
      log(`   标题：${session.title || "新会话"}`);
      log(`   会话 ID：${session.sessionId}`);
      log(`   路径：.deepseek/sessions/${session.sessionId}.json`);
      return session;
    }

    case "history": {
      if (args[0] === "off") { log("🔇 自动打印：关"); return session; }
      if (args[0] === "on") { log("🔊 自动打印：开"); return session; }
      const targetSession = args.includes("-id") ? ctx.store.load(args[args.indexOf("-id") + 1]) : null;
      const msgs = targetSession ? targetSession.messages : (session ? session.messages : []);
      const showAll = args.includes("-a");
      const rIdx = args.indexOf("-r");
      const range = rIdx !== -1 ? parseInt(args[rIdx + 1], 10) || 2 : (parseInt(args[0], 10) || (showAll ? msgs.length : 2));
      const rounds = Math.min(range, showAll ? msgs.length : range);
      const start = Math.max(0, msgs.length - rounds * 2);
      for (let i = start; i < msgs.length; i++) {
        const m = msgs[i];
        if (m.role === "user") log(`\n👤 \x1b[32m${m.content}\x1b[0m`);
        else log(`\n🤖 ${m.content}`);
      }
      return session;
    }

    case "sys": case "system": {
      const env = scanDeepseekDir(ctx.workDir);
      if (args[0] === "-c") {
        const sysFile = path.join(ctx.workDir, ".deepseek", "system.md");
        if (fs.existsSync(sysFile)) {
          fs.unlinkSync(sysFile);
          const newEnv = scanDeepseekDir(ctx.workDir);
          if (session) session.setSystemPrompt(newEnv.systemPrompt);
          if (newEnv.systemSource === "global") {
            log(`✅ 已清除局部提示词\n   当前回退到全局提示词: .deepseek/system-all.md`);
          } else {
            log("✅ 已清除局部提示词\n   当前无任何系统提示词生效");
          }
        } else {
          log("💡 局部提示词不存在，无需清除");
        }
      } else if (args[0] === "-f") {
        const srcPath = args[1];
        if (!srcPath || !fs.existsSync(srcPath)) {
          log(`❌ 源文件不存在: ${srcPath || ""}`);
          return session;
        }
        const isLocal = args.includes("-l");
        const destFile = isLocal ? "system.md" : "system-all.md";
        const destPath = path.join(ctx.workDir, ".deepseek", destFile);
        fs.mkdirSync(path.join(ctx.workDir, ".deepseek"), { recursive: true });
        fs.copyFileSync(srcPath, destPath);
        const newEnv = scanDeepseekDir(ctx.workDir);
        if (session) session.setSystemPrompt(newEnv.systemPrompt);
        log(`✅ 已加载${isLocal ? "局部" : "全局"}提示词: ${destFile}`);
      } else {
        const sysFile = env.systemSource === "local"
          ? path.join(ctx.workDir, ".deepseek", "system.md")
          : env.systemSource === "global"
          ? path.join(ctx.workDir, ".deepseek", "system-all.md")
          : null;
        if (sysFile) {
          const content = readFileIfExists(sysFile);
          const preview = content.length > 500 ? content.slice(0, 500) + "...(已截断)" : content;
          log(`📋 系统提示词（${env.systemSource === "local" ? "局部" : "全局"}）: ${sysFile}`);
          log(preview);
        } else {
          log("📋 当前无系统提示词生效");
        }
      }
      return session;
    }

    case "rj": case "reinject": {
      if (!session) { log("❌ 没有活跃会话"); return session; }
      const mode = args[0] === "-new" ? "new" : args[0] === "-keep" ? "keep" : null;
      if (!mode) { log("❌ 用法: /rj -new 或 /rj -keep"); return session; }
      if (session.reinjectMode) {
        log(`⚠️ 已有待注入提示词（模式：${session.reinjectMode}），确认覆盖？(y/n)`);
        return { type: "confirm", action: "REINJECT", mode } as CommandResult;
      }
      session.setReinjectMode(mode);
      const env = scanDeepseekDir(ctx.workDir);
      const promptLen = env.systemPrompt.length + ctx.toolRegistry.buildToolPrompt().length;
      log(`🔄 下次消息将重新注入提示词（共 ${promptLen} 字，模式：${mode === "new" ? "-new" : "-keep"}）`);
      return session;
    }

    case "t": case "tools": {
      const tools = ctx.toolRegistry.list();
      log("🔧 可用工具：\n");
      tools.forEach((t) => {
        const confirm = (t.name === "write" || t.name === "exec") ? "  [需确认]" : "";
        log(`   ${t.name.padEnd(12)}${t.description}${confirm}`);
      });
      return session;
    }

    case "think": {
      if (!session) { log("❌ 没有活跃会话"); return session; }
      if (args[0] === "on") { session.setThinkEnabled(true); log("🧠 思考模式：开"); }
      else if (args[0] === "off") { session.setThinkEnabled(false); log("🧠 思考模式：关"); }
      else { session.setThinkEnabled(!session.thinkEnabled); log(`🧠 思考模式：${session.thinkEnabled ? "开" : "关"}`); }
      return session;
    }

    case "search": {
      if (!session) { log("❌ 没有活跃会话"); return session; }
      if (args[0] === "on") { session.setSearchEnabled(true); log("🔍 联网搜索：开"); }
      else if (args[0] === "off") { session.setSearchEnabled(false); log("🔍 联网搜索：关"); }
      else { session.setSearchEnabled(!session.searchEnabled); log(`🔍 联网搜索：${session.searchEnabled ? "开" : "关"}`); }
      return session;
    }

    case "raw": {
      ctx.rawMode = !ctx.rawMode;
      log(`📶 原始 SSE 数据流：${ctx.rawMode ? "开（调试用）" : "关"}`);
      return session;
    }

    case "tool": {
      if (!session) { log("❌ 没有活跃会话"); return session; }
      if (args[0] === "on") {
        session.setToolsPrompt(ctx.toolRegistry.buildToolPrompt());
        log("🔧 工具模式：开");
      } else if (args[0] === "off") {
        session.setToolsPrompt("");
        log("🔧 工具模式：关");
      } else {
        log("❌ 用法: /tool on 或 /tool off");
      }
      return session;
    }

    case "auth": {
      const c = ctx.creds;
      if (args[0] === "-s") {
        log("⏳ 正在验证凭证...");
        const { valid, email } = await verifyCredentials(c);
        if (valid) log(`✅ 凭证有效${email ? ` (用户: ${email})` : ""}`);
        else log("❌ 凭证已过期 (401)，使用 /reauth 重新登录");
      } else {
        log("🔑 凭证状态");
        log(`   Cookie:  ✅ 已设置 (${c.cookie.split(";").length} 个 cookies)`);
        log(`   Bearer:  ✅ 已设置 (${c.bearer.slice(0, 6)}...)`);
        log(`   UA:      ✅ ${c.userAgent.slice(0, 40)}...`);
      }
      return session;
    }

    case "reauth": {
      log("⏳ 正在连接 Chrome 调试端口...");
      try {
        const newCreds = await loginDeepseek((msg) => log(`   ⏳ ${msg}`));
        saveCredentials(newCreds);
        ctx.creds = newCreds;
        if (session) session.setClient(newCreds);
        log("✅ 凭证已覆盖保存 → credentials.json");
      } catch (err: any) {
        log(`❌ 登录失败: ${err.message}`);
      }
      return session;
    }

    case "?": case "h": case "help": {
      log("📖 DeepSeek Web CLI 帮助\n");
      log("会话管理:");
      log("  /new  [标题]      创建新会话");
      log("  /load [id]        切换会话（无参数时交互式选择，输 q 退出）");
      log("  /list, /ls        列出所有会话（ID、标题、轮数、时间、fork 信息）");
      log("  /del  [id|--all]  删除会话（无参数时交互式，输入序号/a/q）");
      log("  /parent <id>, /p  手动覆盖续接点（需确认）");
      log("  /fork [id] [标题], /f  分叉新会话");
      log("  /save, /s         手动保存当前会话");
      log("  /history          查看历史 [-r N 最近N轮] [-a 全部] [-id <id> 指定会话] [on/off 开关自动打印]");
      log("\n提示词管理:");
      log("  /system, /sys     查看当前提示词状态");
      log("  /sys -c           清除局部提示词（回退到全局）");
      log("  /sys -f <path>    从文件加载为全局提示词");
      log("  /sys -f <path> -l 从文件加载为局部提示词");
      log("  /reinject, /rj    重新注入提示词 [-new 重置父消息] [-keep 保持续接]");
      log("\n工具:");
      log("  /tools, /t        列出可用工具（read/write/edit/exec）");
      log("  /tool  on/off     切换工具模式（开启后 AI 可使用工具）");
      log("\n凭证:");
      log("  /auth             查看凭证状态（脱敏显示）");
      log("  /auth  -s         发送 API 请求验证凭证有效性");
      log("  /reauth           重新登录获取凭证（覆盖式）");
      log("\n模式切换:");
      log("  /think [on/off]   切换思考模式（默认关，提示符显示 🧠）");
      log("  /search [on/off]  切换联网搜索（默认开，提示符显示 🔍）");
      log("  /raw              切换原始 SSE 数据流（调试用）");
      log("\n系统:");
      log("  /?, /h            显示本帮助");
      log("  /quit, /q         退出（需确认 y/n）");
      log("  /clear            清屏");
      log("  /cd <path>        切换工作目录（自动发现提示词和会话）");
      log("  /pwd              显示当前工作目录");
      log("  !<cmd>            Shell 透传（如 !ls, !echo）");
      return session;
    }

    case "q": case "quit": {
      return { type: "quit" } as CommandResult;
    }

    case "clear": {
      process.stdout.write("\x1b[2J\x1b[H");
      return session;
    }

    case "cd": {
      const dir = args[0];
      if (!dir) { log("❌ 用法: /cd <路径>"); return session; }
      try {
        process.chdir(dir);
        return { type: "cd_switched", dir: process.cwd() } as CommandResult;
      } catch (err: any) {
        log(`❌ 切换失败: ${err.message}`);
      }
      return session;
    }

    case "pwd": {
      log(`📂 当前工作目录：${ctx.workDir}`);
      return session;
    }

    default:
      log(`❌ 未知命令: /${cmd}，输入 /? 查看帮助`);
      log("可用命令: new load ls del p f s history sys rj t think raw auth reauth cd ?,h help q quit clear pwd");
      return session;
  }
}

function displayEvent(event: ParseEvent, rawMode: boolean): void {
  // 原始模式：text_delta 直接输出，其他事件忽略
  if (rawMode) {
    if (event.type === "text_delta") process.stdout.write(event.content);
    return;
  }

  switch (event.type) {
    case "text_delta":
      process.stdout.write(event.content);
      break;
    case "thinking_delta":
      process.stdout.write(`\x1b[36m${event.content}\x1b[0m`);
      break;
    case "tool_call_end":
      console.log(`\n🔧 执行工具: ${event.name} ✅`);
      break;
    case "tool_call_start":
      console.log(`\n🔧 工具调用开始: ${event.name}`);
      break;
    case "message_id":
      break;
    case "title":
      console.log(`\n🔍 会话标题: ${event.title}`);
      break;
    case "error":
      console.error(`\n❌ ${event.message}`);
      break;
    case "end":
      break;
    default:
      break;
  }
}

function getPrompt(session: ChatSession | null): string {
  if (!session) return "💬 新会话 > ";
  const title = session.title || "新会话";
  const thinkIcon = session.thinkEnabled ? " 🧠" : "";
  const searchIcon = session.searchEnabled ? " 🔍" : "";
  return `💬 ${title}${thinkIcon}${searchIcon} > `;
}

function switchWorkspace(
  newDir: string,
  session: ChatSession | null,
  ctx: ReplCtx
): { env: ReturnType<typeof scanDeepseekDir>; session: ChatSession | null } {
  process.chdir(newDir);
  ctx.workDir = newDir;
  if (session) session.save();

  const newStore = new SessionStore(newDir);
  ctx.store = newStore;

  const env = scanDeepseekDir(newDir);
  console.log(`\n📂 工作目录已切换: ${newDir}`);
  console.log(`📋 提示词状态：`);
  console.log(`   🔹 系统提示词（${env.systemSource === "local" ? "局部" : env.systemSource === "global" ? "全局" : "无"}）${env.systemPrompt ? ` ✅ (${env.systemPrompt.length} 字)` : ""}`);

  // 恢复新目录会话
  const currentId = newStore.getCurrentId();
  let newSession: ChatSession | null = null;
  if (currentId) {
    newSession = ChatSession.load(currentId, ctx.client, newStore, ctx.promptBuilder, ctx.toolExecutor);
    if (!newSession) {
      console.log("⚠️ 上次会话已不存在，已创建新会话");
    }
  }
  if (!newSession) {
    newSession = ChatSession.create(ctx.client, newStore, ctx.promptBuilder, ctx.toolExecutor);
    newStore.setCurrentId(newSession.sessionId);
  }
  newSession.setSystemPrompt(env.systemPrompt);
  // 不自动注入工具提示词

  return { env, session: newSession };
}

async function startRepl(): Promise<void> {
  console.log("🚀 DeepSeek Web CLI");
  console.log("输入 /? 查看帮助，输入消息开始对话\n");

  const log = (msg: string) => console.log(`  ⏳ ${msg}`);

  // 凭证就绪
  let creds: Credentials;
  try {
    creds = await ensureCredentials(log);
  } catch (err: any) {
    console.error(`❌ 启动失败: ${err.message}`);
    process.exit(1);
  }
  console.log("✅ 凭证就绪\n");

  // 建所有依赖
  const workDir = process.cwd();
  const client = new DeepSeekClient(creds);
  const store = new SessionStore(workDir);
  const registry = new ToolRegistry();
  registerBuiltinTools(registry);
  const executor = new ToolExecutor(registry);
  const promptBuilder = new PromptBuilder(workDir);

  // 扫描环境
  const env = scanDeepseekDir(workDir);
  console.log(`📂 工作目录: ${workDir}`);
  console.log(`📋 提示词状态：`);
  console.log(`   🔹 系统提示词（${env.systemSource === "local" ? "局部" : env.systemSource === "global" ? "全局" : "无"}）${env.systemPrompt ? ` ✅ (${env.systemPrompt.length} 字)` : ""}`);
  console.log(`   🔹 Skill 提示词:      ${env.skillMdContent ? `✅ (${env.skillMdContent.length} 字)` : "(未找到)"}`);
  console.log(`   🔹 Tool 提示词:       ${env.toolMdContent ? `✅ (${env.toolMdContent.length} 字)` : "(未找到)"}`);
  console.log();

  // 恢复或创建会话
  let session: ChatSession | null = null;
  const currentId = store.getCurrentId();
  if (currentId) {
    session = ChatSession.load(currentId, client, store, promptBuilder, executor);
    if (!session) {
      console.log("⚠️ 上次会话已不存在，已创建新会话");
    }
  }
  if (!session) {
    session = ChatSession.create(client, store, promptBuilder, executor);
    store.setCurrentId(session.sessionId);
  } else {
    console.log(`📎 已打开最近会话: ${session.sessionId} - ${session.title || "新会话"} (${session.messageCount} 轮)`);
    console.log("");
  }
  session.setSystemPrompt(env.systemPrompt);

  // REPL 状态
  let deleteSubMode = false;
  let loadSubMode = false;
  let confirmQuit = false;
  let roomRecoveryMsg: string | null = null;
  let pendingAction: string | null = null;
  let historyOn = true;
  const messageQueue: string[] = [];
  let isSending = false;

  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
    prompt: getPrompt(session),
  });

  session.setRl(rl);

  const ctx: ReplCtx = { client, store, promptBuilder, toolRegistry: registry, toolExecutor: executor, creds, workDir, rl, rawMode: false };

  // 删除子模式处理函数
  const handleDeleteInput = async (input: string) => {
    const trimmed = input.trim();
    if (trimmed === "q" || trimmed === "/q") {
      deleteSubMode = false;
      console.log("已退出删除模式");
      return;
    }
    if (trimmed === "all") {
      console.log("⚠️ 将删除全部会话，确认？(y/n)");
      rl.pause();
      const answer = await new Promise<string>((resolve) => {
        process.stdin.once("data", (buf) => resolve(buf.toString().trim().toLowerCase()));
      });
      rl.resume();
      if (answer === "y" || answer === "yes") {
        const list = store.list();
        for (const s of list) { store.delete(s.id); }
        if (session && !store.load(session.sessionId)) session = null;
        console.log(`✅ 已删除全部 ${list.length} 个会话`);
        deleteSubMode = false;
      }
      return;
    }
    const idx = parseInt(trimmed, 10);
    const list = store.list();
    if (isNaN(idx) || idx < 1 || idx > list.length) {
      console.log("❌ 无效输入，请输入序号、或 a（全部删除）、或 q（退出）");
      rl.prompt();
      return;
    }
    const target = list[idx - 1];
    store.delete(target.id);
    if (session && session.sessionId === target.id) session = null;
    console.log(`✅ 已删除 ${target.id} - ${target.title}`);
  };

  // 消息队列处理
  const processQueue = async () => {
    if (isSending || !session) return;
    while (messageQueue.length > 0) {
      isSending = true;
      const msg = messageQueue.shift()!;

      let needRetry = true;
      let retryCount = 0;
      while (needRetry && retryCount < 2) {
        needRetry = false;
        process.stdout.write("\n");
        for await (const event of session.send(msg, ctx.rawMode)) {
          if (event.type === "room_recovery") {
            const hint = event.historyRounds > 0 ? `（含 ${event.historyRounds} 轮历史）` : "";
            console.log(`\n⚠️ 重建房间并重发消息${hint}？`);
            roomRecoveryMsg = msg;
            rl.setPrompt("(y/n) > ");
            break;
          }
          if (event.type === "error" && event.message.includes("401")) {
            needRetry = true;
            retryCount++;
            console.log(`\n🔑 凭证已过期，正在重新登录...`);
            try {
              creds = await ensureCredentials(log);
              session.setClient(creds);
              ctx.creds = creds;
              console.log("✅ 凭证已刷新，正在重试...");
            } catch (err: any) {
              console.error(`❌ 重登失败: ${err.message}`);
              needRetry = false;
            }
            break;
          }
          displayEvent(event, ctx.rawMode);
        }
      }
      console.log();
    }
    isSending = false;
  };

  // SIGINT
  process.on("SIGINT", () => {
    if (session) {
      session.save();
      store.setCurrentId(session.sessionId);
    }
    console.log("\n👋 再见");
    process.exit(0);
  });

  rl.on("line", async (line: string) => {
    // 退出确认子模式
    if (confirmQuit) {
      const answer = line.trim().toLowerCase();
      if (answer === "y" || answer === "yes") {
        if (session) { session.save(); store.setCurrentId(session.sessionId); }
        console.log("👋 再见");
        rl.close();
        process.exit(0);
        return;
      }
      console.log("已取消");
      confirmQuit = false;
      rl.setPrompt(getPrompt(session));
      rl.prompt();
      return;
    }

    // 房间恢复确认子模式
    if (roomRecoveryMsg) {
      const answer = line.trim().toLowerCase();
      const msg = roomRecoveryMsg;
      roomRecoveryMsg = null;
      if (answer !== "y" && answer !== "yes") {
        console.log("已取消");
        rl.setPrompt(getPrompt(session));
        rl.prompt();
        return;
      }
      // 建新房间
      try {
        if (!session) { session = ChatSession.create(client, store, promptBuilder, executor); }
        const newId = await client.createChatSession();
        session.setId(newId);
        store.setCurrentId(newId);
        // 构建包含历史 + 当前消息的首轮 prompt
        const historyParts: string[] = [];
        const env = scanDeepseekDir(ctx.workDir);
        session.setSystemPrompt(env.systemPrompt);
        for (const m of session.messages) {
          historyParts.push(`${m.role === "user" ? "User" : "Assistant"}: ${m.content}`);
        }
        historyParts.push(`User: ${msg}`);
        const fullPrompt = historyParts.join("\n\n");
        session.setParentMessageId(null);
        // 发送
        const stream = await client.chat(newId, null, fullPrompt,
          session.thinkEnabled, session.searchEnabled);
        const parser = new StreamParser();
        let assistantText = "";
        process.stdout.write("\n");
        for await (const event of parser.parse(stream)) {
          if (event.type === "text_delta" || event.type === "thinking_delta") {
            assistantText += event.content;
            displayEvent(event, ctx.rawMode);
          } else if (event.type === "message_id") {
            session.setParentMessageId(event.id);
          } else if (event.type === "title") {
            session.setTitle(event.title);
          }
        }
        session.pushUserAndAssistantMessages(msg, assistantText);
        session.touch();
        session.save();
      } catch (err: any) {
        console.error(`\n❌ 重建房间失败: ${err.message}`);
      }
      rl.setPrompt(getPrompt(session));
      rl.prompt();
      return;
    }

    // 通用确认子模式 (parent, reinject 等)
    if (pendingAction) {
      const action = pendingAction;
      pendingAction = null;
      const answer = line.trim().toLowerCase();
      if (answer !== "y" && answer !== "yes") {
        console.log("已取消");
        rl.setPrompt(getPrompt(session));
        rl.prompt();
        return;
      }
      if (action.startsWith("PARENT:")) {
        const newId = parseInt(action.slice(7), 10);
        session!.setParentMessageId(newId);
        session!.save();
        console.log("✅ 续接点已更新");
      } else if (action.startsWith("REINJECT:")) {
        const mode = action.slice(10) as "new" | "keep";
        session!.setReinjectMode(mode);
        const env = scanDeepseekDir(ctx.workDir);
        const promptLen = env.systemPrompt.length + registry.buildToolPrompt().length;
        console.log(`🔄 下次消息将重新注入提示词（共 ${promptLen} 字，模式：${mode === "new" ? "-new" : "-keep"}）`);
      } else if (action.startsWith("DEL_SINGLE:")) {
        const id = action.slice(11);
        const target = store.load(id);
        store.delete(id);
        if (session && session.sessionId === id) session = null;
        console.log(`✅ 已删除 ${id} - ${target?.title || ""}`);
      }
      rl.setPrompt(getPrompt(session));
      rl.prompt();
      return;
    }

    // 加载子模式
    if (loadSubMode) {
      const input = line.trim();
      // / 开头的输入当作命令处理，退出子模式
      if (input.startsWith("/")) {
        loadSubMode = false;
        // 不做 return，让后续命令处理器接管
      } else if (input === "q") {
        loadSubMode = false;
        console.log("已退出加载模式");
        rl.prompt();
        return;
      } else {
        const idx = parseInt(input, 10);
        const list = store.list();
        if (isNaN(idx) || idx < 1 || idx > list.length) {
          console.log("❌ 无效序号");
          loadSubMode = false;
          rl.setPrompt(getPrompt(session));
          rl.prompt();
          return;
        }
        const target = list[idx - 1];
        if (session) { session.abort(); session.save(); }
        const loaded = ChatSession.load(target.id, ctx.client, ctx.store, ctx.promptBuilder, ctx.toolExecutor);
        if (loaded) {
          loaded.setRl(rl);
          ctx.store.setCurrentId(loaded.sessionId);
          session = loaded;
          console.log(`📎 已切换到：${loaded.sessionId} - ${loaded.title} (${loaded.messageCount} 轮)`);
        }
        loadSubMode = false;
        rl.setPrompt(getPrompt(session));
        console.log("");
        rl.prompt();
        return;
      }
    }

    // 删除子模式
    if (deleteSubMode) {
      // / 开头的输入当作命令处理，退出子模式
      if (line.trim().startsWith("/")) {
        deleteSubMode = false;
        // 不做 return，让后续命令处理器接管
      } else {
        await handleDeleteInput(line);
        rl.prompt();
        return;
      }
    }

    const trimmed = line.trim();

    // 命令
    if (trimmed.startsWith("/")) {
      // /del /delete /del --all: 进入删除子模式
      const delParts = trimmed.slice(1).trim().split(/\s+/);
      if ((delParts[0] === "del" || delParts[0] === "delete") && (delParts.length === 1 || delParts[1] === "--all")) {
        const list = store.list();
        if (list.length === 0) {
          console.log("暂无保存的会话");
        } else {
          deleteSubMode = true;
          console.log("\n🗑️ 删除会话管理");
          console.log("   输入序号删除 | all 全部 | q 退出\n");
          list.forEach((s, i) => {
            const fork = s.forkedFrom ? ` (fork)` : "";
            console.log(`   [${i + 1}] ${s.id} - ${s.title} (${s.rounds} 轮${fork})`);
          });
        }
      } else {
        const prevSession = session;
        const result = await handleCommand(trimmed, session, ctx);
        if (result && typeof result === "object" && "type" in result) {
          if (result.type === "quit") {
            confirmQuit = true;
            rl.setPrompt("确认退出？(y/n) > ");
            session = prevSession;
          } else if (result.type === "confirm" && result.action === "PARENT") {
            pendingAction = "PARENT:" + result.newId;
            rl.setPrompt("确认？(y/n) > ");
            session = prevSession;
          } else if (result.type === "confirm" && result.action === "DEL_SINGLE") {
            pendingAction = "DEL_SINGLE:" + result.id;
            rl.setPrompt("确认删除？(y/n) > ");
            session = prevSession;
          } else if (result.type === "confirm" && result.action === "REINJECT") {
            pendingAction = "REINJECT:" + result.mode;
            rl.setPrompt("确认覆盖？(y/n) > ");
            session = prevSession;
          } else if (result.type === "load_interactive") {
            loadSubMode = true;
            session = prevSession;
          } else if (result.type === "cd_switched") {
            const sw = switchWorkspace(result.dir, session, ctx);
            session = sw.session;
          }
        } else {
          session = result as ChatSession | null;
          if (session && session !== prevSession) {
            // 不自动注入工具提示词，避免干扰内置搜索
          }
        }
      }
    }
    // Shell 透传
    else if (trimmed.startsWith("!")) {
      const command = trimmed.slice(1).trim();
      if (!command) { rl.prompt(); return; }
      const cwdBefore = process.cwd();
      try {
        execSync(command, { stdio: "inherit" });
      } catch (err: any) {
        console.log(`❌ 命令执行失败: ${err.message}`);
      }
      if (process.cwd() !== cwdBefore) {
        const result = switchWorkspace(process.cwd(), session, ctx);
        session = result.session;
      }
    }
    // 空行
    else if (!trimmed) {
      // 忽略
    }
    // 普通消息
    else if (session) {
      if (!session.sessionId) {
        // 首次发消息确保 _current 更新
        store.setCurrentId(""); // will be set when lazily created
      }
      messageQueue.push(trimmed);
      if (messageQueue.length > 1) {
        console.log("⏳ AI 回复中，消息已排队");
      }
      await processQueue();
    } else {
      session = ChatSession.create(client, store, promptBuilder, executor);
      session.setSystemPrompt(env.systemPrompt);
      // 不自动注入工具提示词，避免干扰内置搜索
      messageQueue.push(trimmed);
      await processQueue();
    }

    // 更新提示符（确认/删除子模式时不覆盖）
    if (!confirmQuit && !pendingAction && !deleteSubMode && !loadSubMode && !roomRecoveryMsg && !ctx.rawMode) {
      rl.setPrompt(getPrompt(session));
    }
    if (!ctx.rawMode) console.log("");
    if (!ctx.rawMode) rl.prompt();
  });

  rl.prompt();
}

async function main(): Promise<void> {
  await startRepl();
}

if (process.argv[1] && (process.argv[1].endsWith("chat.ts") || process.argv[1].endsWith("chat"))) {
  main();
}

